import React from "react"


class AddUser extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            firstname: "",
            info: ""
        }
    }
    render() {
        return (<form className="add-user-form">
            <input placeholder="Имя" onChange={(e) => this.setState({firstname: e.target.value})} />
            <textarea placeholder="Информация о себе" onChange={(e) => this.setState({firstname: e.target.value})} />
            <input placeholder="Профессия" onChange={(e) => this.setState({firstname: e.target.value})} />
            <button type="button" onClick={this.props.AddUser}>Добавить</button>
        </form>)
    }
}



export default AddUser
